import{_ as r}from"./header-B_QLADeV.js";import{_ as a}from"./footer-DXo2OqTi.js";import{_ as n}from"./menu_bar-Dcnc71I7.js";import{_ as o,c as t,b as s,o as i}from"./app-RrIk7Rat.js";const m="/docs/assets/window-poP4DRZn.png",g="/docs/assets/menubar2-BPmpcl4U.png",l={};function p(d,e){return i(),t("div",null,e[0]||(e[0]=[s('<h1 id="user-interface" tabindex="-1"><a class="header-anchor" href="#user-interface"><span>User Interface</span></a></h1><h2 id="window" tabindex="-1"><a class="header-anchor" href="#window"><span>Window</span></a></h2><p>The Cartographer App window consists of the following parts:</p><ol><li><strong>Header (Top Bar)</strong> — contains the title and a dropdown menu button (see number 1 in Image 1).</li><li><strong>Sidebar (Right Panel)</strong> — contains tools for editing and navigation (see number 2 in Image 1).</li><li><strong>Main Working Area</strong> — the central editing space (see number 3 in Image 1).</li><li><strong>Footer (Bottom Bar)</strong> — displays status information about mdivs, page numbers, and zones (see number 4 in Image 1).</li></ol><p><img src="'+m+'" alt="Cartographer App Window"><br><em>Image 1: Layout of the Cartographer App interface</em></p><hr><h2 id="header" tabindex="-1"><a class="header-anchor" href="#header"><span>Header</span></a></h2><p>The header contains a <strong>title</strong> (see number 1 in Image 2) and a <strong>dropdown menu button</strong> (see number 2 in Image 2).</p><p>Clicking the menu reveals options for uploading or downloading MEI files, and importing IIIF image files.<br> Additionally, the header includes buttons to open the <strong>Page Overview</strong> and toggle the <strong>Measure List</strong>.</p><p><img src="'+r+'" alt="Cartographer App Header"><br><em>Image 2: Layout of the Cartographer App header</em></p><hr><h3 id="menu-bar" tabindex="-1"><a class="header-anchor" href="#menu-bar"><span>Menu Bar</span></a></h3><p>Clicking the dropdown menu in the header opens five options (see Image 3):</p><ol><li><strong>Upload MEI File</strong> — upload an MEI file from your local repository (see number 1 in Image 3).</li><li><strong>Import IIIF Manifest</strong> — import an IIIF manifest from a server (see number 2 in Image 3).</li><li><strong>Download MEI File</strong> — download a rendered MEI file from Cartographer (see number 3 in Image 3).</li><li><strong>Show Page Overview</strong> — display all imported images and add more images (see number 4 in Image 3).</li><li><strong>Toggle Measure List</strong> — show or hide a list of all movements and measures in a sidebar (see number 5 in Image 3).</li></ol><p><img src="'+g+'" alt="Header Menu Bar"><br><em>Image 3: Header Menu Bar</em></p><hr><h2 id="footer" tabindex="-1"><a class="header-anchor" href="#footer"><span>Footer</span></a></h2><p>The footer contains:</p><ol><li><strong>Mdiv status display</strong> (see number 1 in Image 9).</li><li><strong>Page navigation buttons</strong> (see number 2 in Image 9).</li><li><strong>Button to jump to a new page</strong> (see number 3 in Image 9).</li><li><strong>Zone counter</strong> — shows the total number of zones on the current page (see number 4 in Image 9).</li></ol><p><img src="'+a+'" alt="Cartographer App Footer"><br><em>Image 9: Cartographer App Footer</em></p><hr><h2 id="sidebar" tabindex="-1"><a class="header-anchor" href="#sidebar"><span>Sidebar</span></a></h2><p>The sidebar contains the following tools:</p><ol><li><strong>Select Regions</strong> — choose and adjust existing regions (see number 1 in Image 10).</li><li><strong>Draw Rectangles</strong> — create new rectangular zones (see number 2 in Image 10).</li><li><strong>Add Measures to Zone</strong> — insert additional measures within the same zone (see number 3 in Image 10).</li><li><strong>Erase Measures</strong> — remove selected measures (see number 4 in Image 10).</li><li><strong>Automatic Measure Detection</strong> — run the detector to identify measures automatically (see number 5 in Image 10).</li><li><strong>Page Navigation</strong> — move between pages of the document (see number 6 in Image 10).</li></ol><p><img src="'+n+'" alt="Sidebar"><br><em>Image 10: The Cartographer App sidebar</em></p>',25)]))}const f=o(l,[["render",p]]),I=JSON.parse('{"path":"/user/UserInterface.html","title":"User Interface","lang":"en-US","frontmatter":{},"git":{"updatedTime":1756211745000,"contributors":[{"name":"Hizkiel","username":"Hizkiel","email":"hizclick@gmail.com","commits":1,"url":"https://github.com/Hizkiel"}],"changelog":[{"hash":"f154f171982bcbf31ca935ebf59603fd9f7ba544","time":1756211745000,"email":"hizclick@gmail.com","author":"Hizkiel","message":"Remove user documentation directory"}]},"filePathRelative":"user/UserInterface.md"}');export{f as comp,I as data};
